using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. Strongly-typed retrieval: JsonSerializerOptions.GetTypeInfo<T>() ---
// Returns JsonTypeInfo<T> directly — no cast needed.

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();

Console.WriteLine($"Type          : {personInfo.Type.Name}");
Console.WriteLine($"Kind          : {personInfo.Kind}");
Console.WriteLine($"Properties    : {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");
Console.WriteLine();

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"Serialized    : {json}");

Person? roundTripped = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Round-tripped : {roundTripped}");
Console.WriteLine();

// --- 2. Probe without throwing: TryGetTypeInfo ---
// Returns false instead of throwing when metadata isn't available.

// Use a resolver that only knows about Person (via source-gen context).
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = PersonContext.Default
};

if (limited.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Person   -> found ({found!.Type.Name})");
else
    Console.WriteLine("Person   -> NOT found");

if (limited.TryGetTypeInfo(typeof(int), out _))
    Console.WriteLine("int      -> found");
else
    Console.WriteLine("int      -> NOT found  (no metadata in this resolver)");

// --- Types ---

public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonContext : JsonSerializerContext;

